function deriveTitle(agentType, prompt) {
  const prefixes = {
    research: "Research:",
    writing: "Draft:",
    planning: "Plan:",
    email: "Email:"
  };
  const prefix = prefixes[agentType] || "Task:";
  const snippet = prompt.slice(0, 60).replace(/\s+/g, " ").trim();
  return `${prefix} ${snippet}${prompt.length > 60 ? "\u2026" : ""}`;
}
